  %rtv.append_cap = phi i64 [ %rtv.out_cap, %rtv.append ], [ %rtv.new_out_cap, %rtv.grow_store ]
  %rtv.out_ptr = getelementptr i8, i8* %rtv.append_out, i64 %rtv.out_len
