asw.have_args:
  %asw.aid1 = call i64 @value_payload(%Value %asw.a1)
  %asw.s1 = call i8* @wam_atom_to_string(i64 %asw.aid1)
  %asw.s1_null = icmp eq i8* %asw.s1, null
  br i1 %asw.s1_null, label %asw.fail, label %asw.have_s1
asw.have_s1:
