  %atc.new_v0 = insertvalue %Value undef, i32 0, 0
  %atc.new_v = insertvalue %Value %atc.new_v0, i64 %atc.new_id, 1
  %atc.a3 = call %Value @wam_get_reg_deref(%WamState* %vm, i32 2)
  %atc.a3_unb = call i1 @value_is_unbound(%Value %atc.a3)
