  %sba.buf = call i8* @wam_arena_alloc(i64 %sba.bufsize)
  %sba.src = getelementptr i8, i8* %sba.str, i64 %sba.b
  call void @llvm.memcpy.p0i8.p0i8.i64(i8* %sba.buf, i8* %sba.src, i64 %sba.l, i1 false)
