  %nco.f_bi_prev = sub i32 %nco.f_bi, 1
  %nco.f_cp_b = getelementptr i8, i8* %nco.fbuf, i32 %nco.f_bi_prev
  %nco.f_ch_b = load i8, i8* %nco.f_cp_b
