  store i8 0, i8* %nco.r_term
  %nco.r_c0 = load i8, i8* %nco.r_buf
  %nco.r_is_neg = icmp eq i8 %nco.r_c0, 45
  br i1 %nco.r_is_neg, label %nco.r_sel_neg, label %nco.r_sel_pos
nco.r_sel_neg:
