  br label %nco.r_first_check
nco.r_sel_pos:
  br label %nco.r_first_check
nco.r_first_check:
  %nco.r_p_start = phi i8* [ %nco.r_pn0, %nco.r_sel_neg ], [ %nco.r_buf, %nco.r_sel_pos ]
  %nco.r_sign = phi i64 [ -1, %nco.r_sel_neg ], [ 1, %nco.r_sel_pos ]
  %nco.r_fc = load i8, i8* %nco.r_p_start
