  %lst.d = call %Value @wam_deref_value(%WamState* %vm, %Value %lst.cur)
  %lst.tag = extractvalue %Value %lst.d, 0
  %lst.is_cmp = icmp eq i32 %lst.tag, 3
  br i1 %lst.is_cmp, label %lst.peek, label %lst.fail
