  call void @wam_arena_ensure()
  %rev.empty_id = load i64, i64* @wam_empty_list_atom_id
  %rev.empty_v0 = insertvalue %Value undef, i32 0, 0
  %rev.empty_v  = insertvalue %Value %rev.empty_v0, i64 %rev.empty_id, 1
  br label %rev.loop
rev.loop:
