alc3.s_alloc:
  %alc3.s_cnt64 = sext i32 %alc3.s_c_cnt to i64
  %alc3.s_arr_bytes = shl i64 %alc3.s_cnt64, 4
  %alc3.s_arr_mem = call i8* @wam_arena_alloc(i64 %alc3.s_arr_bytes)
  %alc3.s_arr = bitcast i8* %alc3.s_arr_mem to %Value*
